function bindDeadlineSettingsEvents() {
  const saveBtn = $("saveExamDateBtn");
  const clearBtn = $("clearExamDateBtn");
  const input = $("examDateInput");
  if (saveBtn && input) {
    saveBtn.addEventListener("click", () => {
      if (!input.value) {
        alert("Выбери дату экзамена или оставь ручной режим 11 недель.");
        return;
      }
      setSettingsProgress({ examDate: input.value, totalWeeks: DEFAULT_REMAINING_WEEKS });
    });
  }
  if (clearBtn) {
    clearBtn.addEventListener("click", () => {
      setSettingsProgress({ examDate: "", totalWeeks: DEFAULT_REMAINING_WEEKS });
    });
  }
}

function renderTopics() {
  const topics = getTopics();
  fillSelect($("sectionFilter"), uniqueValues(DATA.topics, "section"), "Все разделы");
  fillSelect($("levelFilter"), uniqueValues(DATA.topics, "level"), "Все уровни");
  fillSelect($("statusFilter"), topicStatuses, "Все статусы");

  const query = normalize($("topicSearch").value);
  const section = $("sectionFilter").value;
  const level = $("levelFilter").value;
  const status = $("statusFilter").value;

  const filtered = topics.filter((item) => {
    const haystack = normalize([item.id, item.section, item.level, item.macro, item.topic, item.skeleton, item.answerType].join(" "));
    return (!query || haystack.includes(query))
      && (!section || item.section === section)
      && (!level || item.level === level)
      && (!status || item.status === status);
  });

  const done = filtered.filter((item) => item.status === "Готово").length;
  const inProgress = filtered.filter((item) => ["В работе", "Повторить", "Сложно"].includes(item.status)).length;
  $("topicsSummary").textContent = `Показано ${filtered.length} из ${topics.length} тем. Готово: ${done}. В работе/повторить: ${inProgress}.`;

  if (!filtered.length) {
    $("topicsList").innerHTML = `
      <div class="empty-state">
        <strong>Темы не найдены</strong>
        <span>Попробуй изменить поиск или сбросить фильтры.</span>
      </div>
    `;
    return;
  }

  const grouped = filtered.reduce((acc, item) => {
    if (!acc.has(item.section)) acc.set(item.section, []);
    acc.get(item.section).push(item);
    return acc;
  }, new Map());

  $("topicsList").innerHTML = [...grouped.entries()].map(([sectionName, sectionItems]) => {
    const sectionDone = sectionItems.filter((item) => item.status === "Готово").length;
    const sectionPct = percent(sectionDone, sectionItems.length);

    return `
      <details class="topic-section" open>
        <summary class="topic-section-summary">
          <span class="section-title">${escapeHTML(sectionName)}</span>
          <span class="section-stats">${sectionDone}/${sectionItems.length} готово · ${sectionPct}%</span>
        </summary>
        <div class="topic-list">
          ${sectionItems.map((item, index) => renderTopicListItem(item, index)).join("")}
        </div>
      </details>
    `;
  }).join("");

  bindTopicEvents();
}

